import React, { useEffect, useState } from 'react';
import AppLayout from '../../components/shared/AppLayout';
import LoadingSpinner from '../../components/shared/LoadingSpinner';
import api from '../../utils/api';
import toast from 'react-hot-toast';
import { format } from 'date-fns';

export default function AdminDraws() {
  const [draws, setDraws] = useState([]);
  const [loading, setLoading] = useState(true);
  const [running, setRunning] = useState(false);
  const [publishing, setPublishing] = useState(null);

  const fetchDraws = () => {
    api.get('/draws/all')
      .then(r => setDraws(r.data.draws))
      .finally(() => setLoading(false));
  };

  useEffect(() => { fetchDraws(); }, []);

  const handleRunDraw = async () => {
    if (!window.confirm('Run the monthly draw now? This will generate numbers and match all active users.')) return;
    setRunning(true);
    try {
      const r = await api.post('/draws/run');
      toast.success(`Draw generated! ${r.data.winners_count} winner(s) found.`);
      fetchDraws();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to run draw');
    } finally {
      setRunning(false);
    }
  };

  const handlePublish = async (id) => {
    if (!window.confirm('Publish this draw? Winners will be notified.')) return;
    setPublishing(id);
    try {
      await api.put(`/draws/${id}/publish`);
      setDraws(p => p.map(d => d._id === id ? { ...d, status: 'published' } : d));
      toast.success('Draw published! 🎉');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to publish');
    } finally {
      setPublishing(null);
    }
  };

  const currentMonth = new Date().toISOString().slice(0, 7);
  const hasCurrentMonthDraft = draws.some(d => d.month === currentMonth);

  return (
    <AppLayout>
      <div className="max-w-4xl mx-auto space-y-6 animate-slide-up">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div>
            <h1 className="page-title">Draw System</h1>
            <p className="text-charcoal-400 mt-1">Generate and publish monthly draws</p>
          </div>
          <button
            onClick={handleRunDraw}
            disabled={running || hasCurrentMonthDraft}
            className="btn-gold"
            title={hasCurrentMonthDraft ? 'Draw already exists for this month' : ''}
          >
            {running ? (
              <span className="flex items-center gap-2">
                <span className="w-4 h-4 border-2 border-charcoal-900/40 border-t-charcoal-900 rounded-full animate-spin" />
                Running Draw...
              </span>
            ) : hasCurrentMonthDraft ? (
              `✓ ${currentMonth} draw exists`
            ) : (
              '🎲 Run Monthly Draw'
            )}
          </button>
        </div>

        {/* How it works */}
        <div className="card border border-charcoal-700/40 bg-charcoal-800/20">
          <h3 className="text-sm font-semibold text-charcoal-300 mb-3">⚙️ How the Draw Works</h3>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 text-sm text-charcoal-500">
            <div className="flex gap-2"><span className="text-gold-500 font-bold">1.</span><span>5 random numbers (1–45) are generated</span></div>
            <div className="flex gap-2"><span className="text-gold-500 font-bold">2.</span><span>Matched against all active subscribers' scores</span></div>
            <div className="flex gap-2"><span className="text-gold-500 font-bold">3.</span><span>3+ matches = winner. Publish to reveal results.</span></div>
          </div>
        </div>

        {/* Draws list */}
        {loading ? (
          <div className="flex justify-center py-12"><LoadingSpinner size="lg" /></div>
        ) : draws.length === 0 ? (
          <div className="card text-center py-16">
            <div className="text-5xl mb-4">🎲</div>
            <p className="text-charcoal-300 font-medium">No draws yet</p>
            <p className="text-charcoal-500 text-sm mt-1">Run the first monthly draw using the button above</p>
          </div>
        ) : (
          <div className="space-y-4">
            {draws.map(draw => (
              <div key={draw._id} className={`card ${draw.status === 'published' ? 'border-forest-800/40' : 'border-gold-800/30'}`}>
                <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
                  <div className="space-y-3">
                    <div className="flex items-center gap-3 flex-wrap">
                      <h3 className="font-display font-semibold text-white text-lg">
                        Draw — {draw.month}
                      </h3>
                      <span className={draw.status === 'published' ? 'badge-active' : 'badge-gold'}>
                        {draw.status === 'published' ? (
                          <><span className="w-1.5 h-1.5 rounded-full bg-forest-500" /> Published</>
                        ) : (
                          '⏳ Draft'
                        )}
                      </span>
                    </div>
                    <div className="text-sm text-charcoal-400">
                      Generated {format(new Date(draw.date), 'MMMM d, yyyy')}
                      {draw.triggered_by && ` by ${draw.triggered_by.name}`}
                    </div>
                    <div>
                      <p className="text-xs text-charcoal-500 uppercase tracking-wider font-semibold mb-2">Draw Numbers</p>
                      <div className="flex flex-wrap gap-2">
                        {draw.draw_numbers.map((n, i) => (
                          <div key={i} className="draw-number bg-charcoal-800 border-charcoal-600 text-charcoal-200 w-10 h-10">
                            {n}
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>

                  <div className="flex flex-col gap-2 shrink-0">
                    {draw.status === 'draft' && (
                      <button
                        onClick={() => handlePublish(draw._id)}
                        disabled={publishing === draw._id}
                        className="btn-gold text-sm"
                      >
                        {publishing === draw._id ? 'Publishing...' : '📢 Publish Draw'}
                      </button>
                    )}
                    {draw.status === 'published' && (
                      <span className="text-sm text-forest-400 font-medium flex items-center gap-1.5">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                        </svg>
                        Results Live
                      </span>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </AppLayout>
  );
}
